!function() {

    var IMG1 = "data:image/png;base64,";
    
    var IMG2 = "data:image/png;base64,";
    
    var scene=new THREE.Scene();
scene.background=new THREE.Color(0x9b2428);
var cam=new THREE.OrthographicCamera(-1,1,1,-1,0.1,10);
cam.position.z=1;

var renderer=new THREE.WebGLRenderer({canvas:document.getElementById('hero-canvas'),antialias:true});
renderer.setPixelRatio(Math.min(devicePixelRatio,2));
renderer.setSize(innerWidth,innerHeight);
renderer.outputColorSpace=THREE.LinearSRGBColorSpace;

function updateCam(){var a=innerWidth/innerHeight;cam.left=-a;cam.right=a;cam.top=1;cam.bottom=-1;cam.updateProjectionMatrix();}
updateCam();

function fitCover(mesh,tex){
  var ia=tex.image.width/tex.image.height;
  var wa=innerWidth/innerHeight;
  ia>=wa?mesh.scale.set(ia,1,1):mesh.scale.set(wa,wa/ia,1);
}

var MS=1024;
var mc=document.createElement('canvas');
mc.width=mc.height=MS;
var mx=mc.getContext('2d');
mx.fillStyle='#000';mx.fillRect(0,0,MS,MS);
var maskTex=new THREE.CanvasTexture(mc);

var BR=150;
function paint(x,y,dx,dy){
  dx=dx||0;dy=dy||0;
  var spd=Math.hypot(dx,dy);
  var ang=spd>1?Math.atan2(dy,dx):0;
  var str=1+Math.min(spd/(BR*0.4),3);
  mx.save();
  mx.translate(x,y);mx.rotate(ang);mx.scale(str,1);
  var g=mx.createRadialGradient(0,0,0,0,0,BR);
  g.addColorStop(0,'rgba(255,255,255,1)');
  g.addColorStop(0.6,'rgba(255,255,255,0.85)');
  g.addColorStop(1,'rgba(255,255,255,0)');
  mx.globalCompositeOperation='source-over';
  mx.fillStyle=g;
  mx.beginPath();mx.arc(0,0,BR,0,Math.PI*2);mx.fill();
  mx.restore();
  maskTex.needsUpdate=true;
}

var m1=new THREE.MeshBasicMaterial({side:THREE.FrontSide});
var p1=new THREE.Mesh(new THREE.PlaneGeometry(2,2),m1);
p1.position.z=0;scene.add(p1);

var m2=new THREE.ShaderMaterial({
  transparent:true,
  uniforms:{uTex:{value:null},uMask:{value:maskTex},uTime:{value:0}},
  vertexShader:'varying vec2 vUv;void main(){vUv=uv;gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);}',
  fragmentShader:[
    'uniform sampler2D uTex,uMask;uniform float uTime;varying vec2 vUv;',
    'void main(){',
    '  vec2 w=vUv+vec2(sin(vUv.y*5.0+uTime*0.9)*0.02,cos(vUv.x*5.0+uTime*0.7)*0.02);',
    '  vec2 d1=vec2(sin(w.y*4.0+uTime*1.4)*cos(w.x*3.0+uTime*1.1),cos(w.x*3.5+uTime*1.3)*sin(w.y*2.5+uTime*0.9))*0.045;',
    '  vec2 d2=vec2(sin(w.y*11.0-uTime*2.6+w.x*5.0),cos(w.x*9.0+uTime*2.9-w.y*6.0))*0.022;',
    '  float mask=texture2D(uMask,vUv+d1+d2).r;',
    '  float noise=sin(vUv.x*18.0+uTime*2.0)*cos(vUv.y*16.0+uTime*1.7)*0.22+sin(vUv.x*38.0-uTime*3.2)*cos(vUv.y*33.0+uTime*2.6)*0.11;',
    '  float edge=smoothstep(0.05,0.35,mask)*(1.0-smoothstep(0.35,0.65,mask));',
    '  float alpha=smoothstep(0.45,0.55,mask+noise*edge*1.8);',
    '  gl_FragColor=vec4(texture2D(uTex,vUv).rgb,alpha);',
    '}'
  ].join('')
});
var p2=new THREE.Mesh(new THREE.PlaneGeometry(2,2),m2);
p2.position.z=0.01;scene.add(p2);

var loader=new THREE.TextureLoader();
loader.load(IMG1,function(t){t.colorSpace=THREE.NoColorSpace;m1.map=t;m1.needsUpdate=true;fitCover(p1,t);});
loader.load(IMG2,function(t){t.colorSpace=THREE.NoColorSpace;m2.uniforms.uTex.value=t;fitCover(p2,t);});

var mnX=0,mnY=0,smX=0,smY=0,smZ=0,prev=null,lastT=performance.now();
function move(cx,cy){
  lastT=performance.now();
  mnX=(cx/innerWidth-0.5)*2;mnY=-(cy/innerHeight-0.5)*2;
  var wa=innerWidth/innerHeight;
  var wx=((cx/innerWidth)*2-1)*wa,wy=1-(cy/innerHeight)*2;
  var sx=p2.scale.x,sy=p2.scale.y;
  var px=((wx+sx)/(2*sx))*MS,py=((sy-wy)/(2*sy))*MS;
  if(prev){
    var dx=px-prev.x,dy=py-prev.y;
    var steps=Math.max(1,Math.floor(Math.hypot(dx,dy)/(BR*0.25)));
    for(var i=0;i<=steps;i++) paint(prev.x+dx*i/steps,prev.y+dy*i/steps,dx,dy);
  } else paint(px,py,0,0);
  prev={x:px,y:py};
}
window.addEventListener('mousemove',function(e){move(e.clientX,e.clientY);});
window.addEventListener('mouseleave',function(){prev=null;});
window.addEventListener('touchstart',function(e){e.preventDefault();prev=null;move(e.touches[0].clientX,e.touches[0].clientY);},{passive:false});
window.addEventListener('touchmove',function(e){e.preventDefault();move(e.touches[0].clientX,e.touches[0].clientY);},{passive:false});
window.addEventListener('touchend',function(){prev=null;});

var clock=new THREE.Clock();
function tick(){
  var t=clock.getElapsedTime();
  m2.uniforms.uTime.value=t;
  if((performance.now()-lastT)/1000>2){
    var wa=innerWidth/innerHeight,wx=Math.sin(t*1.1)*wa,wy=Math.sin(t*0.7);
    var sx=p2.scale.x,sy=p2.scale.y;
    paint(((wx+sx)/(2*sx))*MS,((sy-wy)/(2*sy))*MS,0,0);
  }
  smX+=(mnX-smX)*0.06;smY+=(mnY-smY)*0.06;
  var d=Math.hypot(mnX,mnY);smZ+=(d-smZ)*0.06;
  p1.position.set(smX*0.012,smY*0.012,-smZ*0.03);
  p2.position.set(smX*0.02,smY*0.02,0.01+smZ*0.05);
  var lk=new THREE.Vector3(smX*0.3,smY*0.3,5);
  p1.lookAt(lk);p2.lookAt(lk);
  mx.globalCompositeOperation='source-over';
  mx.fillStyle='rgba(0,0,0,0.018)';
  mx.fillRect(0,0,MS,MS);
  maskTex.needsUpdate=true;
  renderer.render(scene,cam);
  requestAnimationFrame(tick);
}
tick();

window.addEventListener('resize',function(){
  renderer.setSize(innerWidth,innerHeight);
  renderer.setPixelRatio(Math.min(devicePixelRatio,2));
  updateCam();
  if(m1.map) fitCover(p1,m1.map);
  if(m2.uniforms.uTex.value) fitCover(p2,m2.uniforms.uTex.value);
});


}();